                    name="name" 
                    value={formData.name} 
                    onChange={handleChange}
                    placeholder="Full name"
                    required
                  />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Email</label>
                    <input 
                      name="email" 
                      type="email"
                      value={formData.email} 
                      onChange={handleChange}
                      placeholder="email@example.com"
                    />
                  </div>
                  <div className="form-group">
                    <label>Phone</label>
                    <input 
                      name="phone" 
                      value={formData.phone} 
                      onChange={handleChange}
                      placeholder="+1 234 567 890"
                    />
                  </div>
                </div>
                <div className="form-group">
                  <label>Address</label>
                  <input 
                    name="address" 
                    value={formData.address} 
                    onChange={handleChange}
                    placeholder="Street address"
                  />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Category</label>
                    <select name="category" value={formData.category} onChange={handleChange}>
                      {categories.map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                      <option value="Uncategorized">Uncategorized</option>
                      <option value="Work">Work</option>
                      <option value="Personal">Personal</option>
                      <option value="Family">Family</option>
                      <option value="Business">Business</option>
                    </select>
                  </div>
                </div>
                <div className="form-group">
                  <label>Notes</label>
                  <textarea 
                    name="notes" 
                    value={formData.notes} 
                    onChange={handleChange}
                    placeholder="Additional notes..."
                  />
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={onClose}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary">
                  {contact ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      );
    };

    // Contact Card Component
    const ContactCard = ({ contact, categories, onEdit, onDelete }) => {
      const categoryClass = contact.category.toLowerCase().replace(/\s+/g, '-');

      return (
        <div className="contact-card">
          <div className="contact-header">
            <div>
              <div className="contact-name">{contact.name}</div>
              <span className={`contact-category ${categoryClass}`}>{contact.category}</span>
            </div>
          </div>
          <div className="contact-details">
            {contact.email && (
              <div className="contact-detail">
                <MailIcon />
                <span>{contact.email}</span>
              </div>
            )}
            {contact.phone && (
              <div className="contact-detail">
                <PhoneIcon />
                <span>{contact.phone}</span>
              </div>
            )}
            {contact.address && (
              <div className="contact-detail">
                <MapPinIcon />
                <span>{contact.address}</span>
              </div>
            )}
            {contact.notes && (
              <div className="contact-detail">
                <NoteIcon />
                <span>{contact.notes.length > 60 ? contact.notes.substring(0, 60) + '...' : contact.notes}</span>
              </div>
            )}
          </div>
          <div className="contact-actions">
            <button className="btn btn-secondary" onClick={() => onEdit(contact)}>
              Edit
            </button>
            <button className="btn btn-danger" onClick={() => onDelete(contact)}>
              Delete
            </button>
          </div>
        </div>
      );
    };

    // Main App
    const App = () => {
      const [contacts, setContacts] = useState([]);
      const [categories, setCategories] = useState(['Uncategorized', 'Work', 'Personal', 'Family', 'Business']);
      const [stats, setStats] = useState({ total: 0, byCategory: {} });
      const [loading, setLoading] = useState(true);
      const [error, setError] = useState(null);
      const [searchQuery, setSearchQuery] = useState('');
      const [selectedCategory, setSelectedCategory] = useState('all');
      const [modalOpen, setModalOpen] = useState(false);
      const [editingContact, setEditingContact] = useState(null);
      const [message, setMessage] = useState(null);

      const showMessage = (text, type = 'success') => {
        setMessage({ text, type });
        setTimeout(() => setMessage(null), 3000);
      };

      const loadContacts = useCallback(async () => {
        try {
          setLoading(true);
          let result;
          if (searchQuery || selectedCategory !== 'all') {
            result = await api.search(searchQuery, selectedCategory === 'all' ? null : selectedCategory);
          } else {
            result = await api.getAll();
          }
          if (result.success) {
            setContacts(result.data);
          } else {
            setError(result.error);
          }
        } catch (err) {
          setError('Failed to load contacts: ' + err.message);
        } finally {
          setLoading(false);
        }
      }, [searchQuery, selectedCategory]);

      const loadCategories = useCallback(async () => {
        try {
          const result = await api.getCategories();
          if (result.success && result.data.categories.length > 0) {
            setCategories(result.data.categories);
            setStats({ total: result.data.total, byCategory: result.data.byCategory });
          }
        } catch (err) {
          console.error('Failed to load categories:', err);
        }
      }, []);

      useEffect(() => {
        loadContacts();
      }, [loadContacts]);

      useEffect(() => {
        loadCategories();
      }, [loadCategories]);

      const handleCreate = async (data) => {
        try {
          const result = await api.create(data);
          if (result.success) {
            showMessage('Contact created successfully!');
            setModalOpen(false);
            loadContacts();
            loadCategories();
          } else {
            setError(result.error);
          }
        } catch (err) {
          setError('Failed to create contact');
        }
      };

      const handleUpdate = async (data) => {
        if (!editingContact) return;
        try {
          const result = await api.update(editingContact.id, data);
          if (result.success) {
            showMessage('Contact updated successfully!');
            setModalOpen(false);
            setEditingContact(null);
            loadContacts();
            loadCategories();
          } else {
            setError(result.error);
          }
        } catch (err) {
          setError('Failed to update contact');
        }
      };

      const handleDelete = async (contact) => {
        if (!confirm(`Delete "${contact.name}"?`)) return;
        try {
          const result = await api.delete(contact.id);
          if (result.success) {
            showMessage('Contact deleted successfully!');
            loadContacts();
            loadCategories();
          } else {
            setError(result.error);
          }
        } catch (err) {
          setError('Failed to delete contact');
        }
      };

      const openCreateModal = () => {
        setEditingContact(null);
        setModalOpen(true);
      };

      const openEditModal = (contact) => {
        setEditingContact(contact);
        setModalOpen(true);
      };

      const closeModal = () => {
        setModalOpen(false);
        setEditingContact(null);
      };

      const uniqueCategories = ['all', ...new Set([...categories, 'Work', 'Personal', 'Family', 'Business', 'Uncategorized'])];

      return (
        <div className="container">
          <div className="header">
            <h1>NEXUS Contacts</h1>
            <p>Search and organize your network</p>
          </div>

          {message && (
            <div className={message.type === 'error' ? 'error-message' : 'success-message'}>
              {message.text}
            </div>
          )}

          <div className="stats-bar">
            <div className="stat-card">
              <div className="number">{stats.total}</div>
              <div className="label">Total Contacts</div>
            </div>
            {categories.slice(0, 3).map(cat => (
              <div key={cat} className="stat-card">
                <div className="number">{stats.byCategory[cat] || 0}</div>
                <div className="label">{cat}</div>
              </div>
            ))}
          </div>

          <div className="controls">
            <div className="search-box">
              <SearchIcon />
              <input 
                type="text" 
                placeholder="Search by name, email, phone..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <select 
              className="filter-select"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              <option value="all">All Categories</option>
              {uniqueCategories.filter(c => c !== 'all').map(cat => (
                <option key={cat} value={cat}>{cat}</option>
              ))}
            </select>
            <button className="btn btn-primary" onClick={openCreateModal}>
              <PlusIcon />
              Add Contact
            </button>
          </div>

          <div className="category-pills">
            {uniqueCategories.map(cat => (
              <button
                key={cat}
                className={`category-pill ${selectedCategory === cat ? 'active' : ''}`}
                onClick={() => setSelectedCategory(cat)}
              >
                {cat === 'all' ? 'All' : cat}
                {cat !== 'all' && stats.byCategory[cat] && (
                  <span style={{marginLeft: 6, opacity: 0.7}}>({stats.byCategory[cat]})</span>
                )}
              </button>
            ))}
          </div>

          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : error ? (
            <div className="error-message">
              <p>{error}</p>
              <button className="btn btn-primary" onClick={loadContacts} style={{marginTop: '1rem'}}>
                Retry
              </button>
            </div>
          ) : contacts.length === 0 ? (
            <div className="empty-state">
              <EmptyStateIcon />
              <h3>{searchQuery ? 'No contacts found' : 'No contacts yet'}</h3>
              <p>{searchQuery ? 'Try a different search term' : 'Add your first contact to get started'}</p>
              {!searchQuery && (
                <button className="btn btn-primary" onClick={openCreateModal} style={{marginTop: '1rem'}}>
                  <PlusIcon />
                  Add Contact
                </button>
              )}
            </div>
          ) : (
            <div className="contacts-grid">
              {contacts.map(contact => (
                <ContactCard
                  key={contact.id}
                  contact={contact}
                  categories={categories}
                  onEdit={openEditModal}
                  onDelete={handleDelete}
                />
              ))}
            </div>
          )}

          {modalOpen && (
            <ContactModal
              contact={editingContact}
              categories={categories}
              onClose={closeModal}
              onSave={editingContact ? handleUpdate : handleCreate}
            />
          )}
        </div>
      );
    };

    // Render the app
    const root = ReactDOM.createRoot(document.getElementById('root'));
    root.render(<App />);
  </script>
</body>
</html>
EOF"}

